import { GoogleGenAI } from "@google/genai";
import { ARCHIE_SYSTEM_INSTRUCTION } from '../constants';

export const getArchieResponseStream = async (message: string, history: {role: 'user' | 'model', text: string}[] = []) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Transform history to the format expected by the API
  const contents = history.map(h => ({
    role: h.role,
    parts: [{ text: h.text }]
  }));

  // Add the current message
  contents.push({
    role: 'user',
    parts: [{ text: message }]
  });

  try {
    const result = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: contents,
      config: {
        systemInstruction: ARCHIE_SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }],
        thinkingConfig: { thinkingBudget: 1024 }, // Allow some reasoning for complex neutrality questions
        temperature: 0.7,
      },
    });

    return result;
  } catch (error) {
    console.error("Archie Streaming Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Phone, Send, Loader2, Sparkles, Globe, Shield, History, Terminal } from 'lucide-react';
import { ChatMessage } from '../types';
import { getArchieResponseStream } from '../services/geminiService';

export const Archie: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: "Connection established. I am Archie, Custodian of the IAN Spirit. \n\nI can retrieve archival logic or analyze current global events through the lens of Article 3 Neutrality. How shall we begin?",
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [streamingText, setStreamingText] = useState('');
  const [isTerminalMode, setIsTerminalMode] = useState(true);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, streamingText]);

  const handleSend = async (textInput: string = input) => {
    if (!textInput.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: textInput,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);
    setStreamingText('');

    try {
      // Prepare history for API
      const history = messages.map(m => ({
        role: m.role as 'user' | 'model',
        text: m.text
      }));

      const stream = await getArchieResponseStream(userMsg.text, history);

      let fullResponse = '';
      for await (const chunk of stream) {
        const text = chunk.text;
        if (text) {
          fullResponse += text;
          setStreamingText(fullResponse);
        }
      }

      const botMsg: ChatMessage = {
        id: Date.now().toString(),
        role: 'model',
        text: fullResponse,
        timestamp: new Date()
      };

      setMessages(prev => [...prev, botMsg]);
      setStreamingText('');
    } catch (error) {
      console.error(error);
      const errorMsg: ChatMessage = {
        id: Date.now().toString(),
        role: 'model',
        text: "Signal interference detected. Please try your query again.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className={`flex flex-col h-[700px] border-2 shadow-2xl transition-all duration-500 rounded-xl overflow-hidden ${
      isTerminalMode ? 'bg-zinc-950 border-zinc-800' : 'bg-vault-paper border-vault-mahogany'
    }`}>
      {/* Header */}
      <div className={`p-4 flex items-center justify-between border-b ${
        isTerminalMode ? 'bg-zinc-900/50 border-zinc-800' : 'bg-vault-mahogany border-vault-mahogany'
      }`}>
        <div className="flex items-center space-x-4">
          <div className={`p-2 rounded-lg ${isTerminalMode ? 'bg-emerald-500/10' : 'bg-vault-amber/20'}`}>
            <Terminal className={`w-6 h-6 ${isTerminalMode ? 'text-emerald-500' : 'text-vault-amber'}`} />
          </div>
          <div>
            <h3 className={`font-serif text-xl tracking-tight ${isTerminalMode ? 'text-emerald-500' : 'text-vault-amber'}`}>
              Archie <span className="text-[10px] opacity-50 uppercase tracking-[0.3em] font-sans">v3.1-Neutrality</span>
            </h3>
            <div className="flex items-center space-x-2">
              <span className={`w-1.5 h-1.5 rounded-full animate-pulse ${isTerminalMode ? 'bg-emerald-500' : 'bg-vault-amber'}`}></span>
              <p className={`text-[10px] uppercase tracking-widest ${isTerminalMode ? 'text-emerald-500/60' : 'text-vault-amber/60'}`}>
                Archive Link: Active • Grounding: Online
              </p>
            </div>
          </div>
        </div>
        <button 
          onClick={() => setIsTerminalMode(!isTerminalMode)}
          className={`px-3 py-1 rounded text-[10px] uppercase font-bold tracking-widest border transition-all ${
            isTerminalMode ? 'border-emerald-500/30 text-emerald-500/70 hover:bg-emerald-500/10' : 'border-vault-amber/30 text-vault-amber/70 hover:bg-vault-amber/10'
          }`}
        >
          {isTerminalMode ? 'Classic View' : 'Terminal View'}
        </button>
      </div>

      {/* Messages Area */}
      <div 
        ref={scrollRef} 
        className={`flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth ${
          isTerminalMode ? 'bg-zinc-950' : "bg-[url('https://www.transparenttextures.com/patterns/aged-paper.png')]"
        }`}
      >
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}>
            <div className={`max-w-[85%] relative group`}>
               <div className={`p-5 rounded-2xl ${
                 msg.role === 'user' 
                   ? (isTerminalMode ? 'bg-zinc-800 text-zinc-100 border border-zinc-700' : 'bg-white text-slate-800 shadow-md') 
                   : (isTerminalMode ? 'bg-zinc-900/50 border border-zinc-800 text-emerald-400 font-mono text-sm' : 'bg-stone-50 border border-stone-200 text-vault-charcoal font-serif text-lg')
               }`}>
                 <p className="leading-relaxed whitespace-pre-wrap">{msg.text}</p>
                 <div className="mt-3 flex items-center justify-between opacity-40 text-[9px] uppercase tracking-widest font-sans">
                   <span>{msg.role === 'model' ? 'ARCHIVE_CORE' : 'MEMBER_ID: REDACTED'}</span>
                   <span>{msg.timestamp.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                 </div>
               </div>
               {msg.role === 'model' && (
                 <div className="absolute -left-2 -bottom-2">
                   <Shield className={`w-4 h-4 ${isTerminalMode ? 'text-emerald-900' : 'text-vault-amber/20'}`} />
                 </div>
               )}
            </div>
          </div>
        ))}

        {streamingText && (
          <div className="flex justify-start animate-in fade-in">
            <div className={`max-w-[85%] p-5 rounded-2xl border ${
               isTerminalMode ? 'bg-zinc-900/50 border-emerald-500/20 text-emerald-400 font-mono text-sm' : 'bg-stone-50 border-vault-amber/20 text-vault-charcoal font-serif text-lg'
            }`}>
              <p className="leading-relaxed whitespace-pre-wrap">{streamingText}</p>
              <div className="mt-2 flex items-center space-x-1">
                 <span className={`w-1 h-3 animate-pulse ${isTerminalMode ? 'bg-emerald-500' : 'bg-vault-amber'}`}></span>
              </div>
            </div>
          </div>
        )}

        {isLoading && !streamingText && (
          <div className="flex justify-start">
            <div className={`flex items-center space-x-3 px-4 py-2 rounded-full border ${
              isTerminalMode ? 'bg-zinc-900 border-zinc-800 text-emerald-500/70' : 'bg-stone-100 border-stone-200 text-stone-500 font-serif italic'
            }`}>
              <Loader2 className="w-4 h-4 animate-spin" />
              <span className="text-[10px] uppercase tracking-widest font-bold">Consulting Grounding Engine...</span>
            </div>
          </div>
        )}
      </div>

      {/* Suggestion Chips */}
      <div className={`px-4 py-3 flex space-x-3 overflow-x-auto border-t scrollbar-hide ${
        isTerminalMode ? 'bg-zinc-900 border-zinc-800' : 'bg-stone-50 border-stone-200'
      }`}>
         {[
           { label: "Grounding: Recent Cyber Trends", icon: Globe, q: "What are the latest global cybercrime trends in the news?" },
           { label: "Charter: Article 3 Deep Dive", icon: Shield, q: "Explain the current challenges to Article 3 neutrality." },
           { label: "Archive: Red Notice History", icon: History, q: "Tell me about the origin of the Red Notice system." }
         ].map((chip, i) => (
           <button 
             key={i} 
             onClick={() => handleSend(chip.q)}
             className={`flex items-center space-x-2 px-3 py-1.5 rounded-lg border text-[10px] uppercase tracking-wider whitespace-nowrap transition-all ${
               isTerminalMode 
                ? 'bg-zinc-800 border-zinc-700 text-zinc-400 hover:text-emerald-400 hover:border-emerald-500/50' 
                : 'bg-white border-stone-200 text-stone-600 hover:text-vault-mahogany hover:border-vault-amber shadow-sm'
             }`}
           >
             <chip.icon className="w-3 h-3" />
             <span>{chip.label}</span>
           </button>
         ))}
      </div>

      {/* Input Area */}
      <div className={`p-6 border-t ${
        isTerminalMode ? 'bg-zinc-950 border-zinc-800' : 'bg-stone-200 border-vault-mahogany/30'
      }`}>
        <div className="flex items-center space-x-4">
          <div className="flex-1 relative group">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder={isTerminalMode ? "EXECUTE QUERY..." : "Speak with the Concierge..."}
              className={`w-full px-6 py-4 rounded-xl border focus:outline-none focus:ring-2 transition-all ${
                isTerminalMode 
                  ? 'bg-zinc-900 border-zinc-800 text-emerald-500 placeholder:text-emerald-900/50 focus:ring-emerald-500/20 font-mono' 
                  : 'bg-white border-stone-300 text-slate-800 focus:ring-vault-mahogany/20 font-serif italic'
              }`}
            />
          </div>
          <button 
            onClick={() => handleSend()}
            disabled={isLoading}
            className={`p-4 rounded-xl transition-all shadow-lg active:scale-95 disabled:opacity-50 ${
              isTerminalMode 
                ? 'bg-emerald-600 text-zinc-950 hover:bg-emerald-500' 
                : 'bg-vault-mahogany text-vault-amber hover:brightness-110'
            }`}
          >
            <Send className="w-6 h-6" />
          </button>
        </div>
        <p className={`text-[9px] text-center mt-3 uppercase tracking-[0.2em] font-bold ${
          isTerminalMode ? 'text-emerald-900' : 'text-stone-500'
        }`}>
          Archie is powered by IAN-Neutrality LLM. Grounding provided by Google Search.
        </p>
      </div>

      <style>{`
        .scrollbar-hide::-webkit-scrollbar { display: none; }
        .scrollbar-hide { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

