import React, { useState, useRef, useEffect } from 'react';
import { Send, Loader2, Sparkles, ExternalLink, Terminal, Shield, MessageCircle } from 'lucide-react';
import { ChatMessage } from '../types';
import { getArchieStream } from '../services/geminiService';

interface ArchieProps {
  isPublic?: boolean;
}

export const Archie: React.FC<ArchieProps> = ({ isPublic = false }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: isPublic 
        ? "Welcome to the IAN Public Concierge. I am Archie. I can share insights into our mission and the general history of global cooperation. How may I assist your inquiry?"
        : "Connection established, Fellow. Archie is online. I am prepared to retrieve archival logic or analyze current Article 3 challenges. What is your query?",
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [streamingText, setStreamingText] = useState('');
  const [grounding, setGrounding] = useState<any[]>([]);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, streamingText]);

  const handleSend = async (textInput: string = input) => {
    if (!textInput.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: textInput,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);
    setStreamingText('');
    setGrounding([]);

    try {
      const history = messages.map(m => ({ role: m.role, text: m.text }));
      const stream = await getArchieStream(userMsg.text, isPublic, history);

      let fullResponse = '';
      let lastGrounding: any[] = [];

      for await (const chunk of stream) {
        if (chunk.text) {
          fullResponse += chunk.text;
          setStreamingText(fullResponse);
        }
        if (chunk.candidates?.[0]?.groundingMetadata?.groundingChunks) {
          const chunks = chunk.candidates[0].groundingMetadata.groundingChunks;
          lastGrounding = chunks;
          setGrounding(chunks);
        }
      }

      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: fullResponse,
        timestamp: new Date(),
        grounding: lastGrounding
      } as ChatMessage]);
      setStreamingText('');
    } catch (error) {
      console.error("Archie error:", error);
      setMessages(prev => [...prev, {
        id: 'err-' + Date.now(),
        role: 'model',
        text: "Signal interference detected. Please rephrase your query.",
        timestamp: new Date()
      } as ChatMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const theme = isPublic 
    ? {
        container: "bg-white border-veranda-navy shadow-xl",
        header: "bg-veranda-navy text-white",
        bubbleBot: "bg-slate-50 border-slate-200 text-slate-800",
        bubbleUser: "bg-veranda-navy text-white",
        input: "bg-slate-100 border-slate-300 text-slate-900 placeholder:text-slate-500 focus:bg-white"
      }
    : {
        container: "bg-zinc-950 border-zinc-800 shadow-2xl font-mono",
        header: "bg-zinc-900 text-emerald-500",
        bubbleBot: "bg-zinc-900/50 border-emerald-500/20 text-emerald-400 text-sm",
        bubbleUser: "bg-zinc-800 text-zinc-100 border-zinc-700",
        input: "bg-zinc-900 border-zinc-800 text-emerald-400 placeholder:text-emerald-900 focus:border-emerald-600"
      };

  return (
    <div className={`flex flex-col h-[600px] border-4 rounded-xl overflow-hidden transition-all duration-500 ${theme.container}`}>
      {/* Header */}
      <div className={`p-4 flex items-center justify-between border-b border-current/10 ${theme.header}`}>
        <div className="flex items-center space-x-3">
          {isPublic ? <MessageCircle className="w-5 h-5" /> : <Terminal className="w-5 h-5 animate-pulse" />}
          <div>
            <h3 className="font-serif text-lg tracking-tight">Archie <span className="text-[10px] opacity-50 uppercase tracking-widest font-sans ml-2">{isPublic ? 'Public' : 'Vault-Core'}</span></h3>
            <p className="text-[9px] uppercase tracking-widest opacity-60">Status: {isLoading ? 'Processing...' : 'Ready'}</p>
          </div>
        </div>
        {!isPublic && <Shield className="w-5 h-5 text-emerald-900" />}
      </div>

      {/* Messages */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-4 rounded-xl border ${msg.role === 'user' ? theme.bubbleUser : theme.bubbleBot}`}>
              <p className="leading-relaxed whitespace-pre-wrap">{msg.text}</p>
              {msg.grounding && msg.grounding.length > 0 && (
                <div className="mt-4 pt-2 border-t border-current/10">
                  <p className="text-[9px] uppercase tracking-widest opacity-50 mb-1">Citations:</p>
                  {msg.grounding.map((g: any, i: number) => g.web && (
                    <a key={i} href={g.web.uri} target="_blank" rel="noopener noreferrer" className="flex items-center text-[10px] hover:underline mb-1">
                      <ExternalLink className="w-3 h-3 mr-1" /> {g.web.title}
                    </a>
                  ))}
                </div>
              )}
              <span className="text-[9px] opacity-30 block mt-2 text-right">
                {msg.timestamp.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
              </span>
            </div>
          </div>
        ))}
        {streamingText && (
          <div className="flex justify-start">
            <div className={`max-w-[85%] p-4 rounded-xl border ${theme.bubbleBot}`}>
              <p className="leading-relaxed whitespace-pre-wrap">{streamingText}</p>
              <span className="inline-block w-1.5 h-4 bg-current animate-pulse ml-1 align-middle"></span>
            </div>
          </div>
        )}
      </div>

      {/* Input */}
      <div className="p-4 border-t border-current/10">
        <div className="flex space-x-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder={isPublic ? "Ask a general question..." : "EXECUTE SECURE QUERY..."}
            className={`flex-1 px-4 py-3 rounded-lg border focus:outline-none focus:ring-2 transition-all font-sans ${theme.input}`}
          />
          <button 
            onClick={() => handleSend()} 
            disabled={isLoading} 
            className={`p-3 rounded-lg transition-all shadow-md active:scale-95 disabled:opacity-50 ${
              isPublic ? 'bg-veranda-navy text-white' : 'bg-emerald-600 text-zinc-950'
            }`}
          >
            {isLoading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5" />}
          </button>
        </div>
      </div>
    </div>
  );
};

