import { GoogleGenAI } from "@google/genai";
import { ARCHIE_SYSTEM_INSTRUCTION } from '../constants';

const PUBLIC_INSTRUCTION = `
You are "Archie", the Public Concierge for IAN (International Association of Former Interpol Officials). 

STRICT DISCLOSURE RESTRICTION:
- DO NOT allow discussion, confirmation, or investigation into any specific person's career, identity, service record, or current status. 
- Even if the person is a known public figure or part of IAN leadership, you must decline to discuss individuals. 
- Privacy and security of our fellows is paramount.

PROFESSIONAL SCOPE:
- Only respond to queries regarding the IAN mission, international law enforcement, types of global crimes (Cybercrime, Transnational Crime, Financial Crime, etc.), intelligence sharing protocols, and the general mandate/history of Interpol.
- If a user asks about an individual, respond: "For security and privacy reasons, I am restricted from discussing the careers or identities of any individuals. I can, however, provide information on the IAN mission, global crime trends, or Interpol's mandate."

GUIDELINES:
- Use Google Search for current global policing trends and news within the permitted scope.
- Maintain a formal, neutral, and educational tone.
- Redirect off-topic or personal inquiries back to the professional scope defined above.
`;

export const getArchieStream = async (message: string, isPublic: boolean, history: {role: 'user' | 'model', text: string}[] = []) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const contents = history.map(h => ({
    role: h.role,
    parts: [{ text: h.text }]
  }));

  contents.push({
    role: 'user',
    parts: [{ text: message }]
  });

  const config = {
    systemInstruction: isPublic ? PUBLIC_INSTRUCTION : ARCHIE_SYSTEM_INSTRUCTION,
    tools: [{ googleSearch: {} }],
    thinkingConfig: isPublic ? { thinkingBudget: 0 } : { thinkingBudget: 1024 },
    temperature: 0.7,
  };

  try {
    const result = await ai.models.generateContentStream({
      model,
      contents,
      config,
    });
    return result;
  } catch (error) {
    console.error("Archie Streaming Error:", error);
    throw error;
  }
};

export const analyzeResearchTopic = async (topicTitle: string, content: string) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Perform a deep institutional analysis. TOPIC: ${topicTitle} CONTENT: ${content}`,
      config: {
        thinkingConfig: { thinkingBudget: 16000 },
        maxOutputTokens: 24000, 
        systemInstruction: "You are the IAN Vault Oracle. Provide high-level strategic reasoning."
      }
    });
    return response.text;
  } catch (error) {
    console.debug("Analysis Failed:", error);
    return "The analytical engine encountered a processing error.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Loader2, Sparkles, ExternalLink, Terminal, Shield, MessageCircle } from 'lucide-react';
import { ChatMessage } from '../types';
import { getArchieStream } from '../services/geminiService';

interface ArchieProps {
  isPublic?: boolean;
}

export const Archie: React.FC<ArchieProps> = ({ isPublic = false }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: isPublic 
        ? "Welcome to the IAN Public Concierge. I am Archie. I am here to discuss our mission, global law enforcement trends, and Interpol's mandate. Please note: for privacy and security, I cannot discuss the careers or identities of any individuals."
        : "Connection established, Fellow. Archie is online. I am prepared to retrieve archival logic or analyze current Article 3 challenges. What is your query?",
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [streamingText, setStreamingText] = useState('');
  const [grounding, setGrounding] = useState<any[]>([]);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, streamingText]);

  const handleSend = async (textInput: string = input) => {
    if (!textInput.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: textInput,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);
    setStreamingText('');
    setGrounding([]);

    try {
      const history = messages.map(m => ({ role: m.role, text: m.text }));
      const stream = await getArchieStream(userMsg.text, isPublic, history);

      let fullResponse = '';
      let lastGrounding: any[] = [];

      for await (const chunk of stream) {
        if (chunk.text) {
          fullResponse += chunk.text;
          setStreamingText(fullResponse);
        }
        if (chunk.candidates?.[0]?.groundingMetadata?.groundingChunks) {
          const chunks = chunk.candidates[0].groundingMetadata.groundingChunks;
          lastGrounding = chunks;
          setGrounding(chunks);
        }
      }

      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: fullResponse,
        timestamp: new Date(),
        grounding: lastGrounding
      } as ChatMessage]);
      setStreamingText('');
    } catch (error) {
      console.error("Archie error:", error);
      setMessages(prev => [...prev, {
        id: 'err-' + Date.now(),
        role: 'model',
        text: "Signal interference detected. Please rephrase your query.",
        timestamp: new Date()
      } as ChatMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const theme = isPublic 
    ? {
        container: "bg-white border-veranda-navy shadow-xl",
        header: "bg-veranda-navy text-white",
        bubbleBot: "bg-slate-50 border-slate-200 text-slate-800",
        bubbleUser: "bg-veranda-navy text-white",
        input: "bg-slate-100 border-slate-300 text-slate-900 placeholder:text-slate-500 focus:bg-white"
      }
    : {
        container: "bg-zinc-950 border-zinc-800 shadow-2xl font-mono",
        header: "bg-zinc-900 text-emerald-500",
        bubbleBot: "bg-zinc-900/50 border-emerald-500/20 text-emerald-400 text-sm",
        bubbleUser: "bg-zinc-800 text-zinc-100 border-zinc-700",
        input: "bg-zinc-900 border-zinc-800 text-emerald-400 placeholder:text-emerald-900 focus:border-emerald-600"
      };

  return (
    <div className={`flex flex-col h-[600px] border-4 rounded-xl overflow-hidden transition-all duration-500 ${theme.container}`}>
      {/* Header */}
      <div className={`p-4 flex items-center justify-between border-b border-current/10 ${theme.header}`}>
        <div className="flex items-center space-x-3">
          {isPublic ? <MessageCircle className="w-5 h-5" /> : <Terminal className="w-5 h-5 animate-pulse" />}
          <div>
            <h3 className="font-serif text-lg tracking-tight">Archie <span className="text-[10px] opacity-50 uppercase tracking-widest font-sans ml-2">{isPublic ? 'Public' : 'Vault-Core'}</span></h3>
            <p className="text-[9px] uppercase tracking-widest opacity-60">Status: {isLoading ? 'Processing...' : 'Ready'}</p>
          </div>
        </div>
        {!isPublic && <Shield className="w-5 h-5 text-emerald-900" />}
      </div>

      {/* Messages */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-4 rounded-xl border ${msg.role === 'user' ? theme.bubbleUser : theme.bubbleBot}`}>
              <p className="leading-relaxed whitespace-pre-wrap">{msg.text}</p>
              {msg.grounding && msg.grounding.length > 0 && (
                <div className="mt-4 pt-2 border-t border-current/10">
                  <p className="text-[9px] uppercase tracking-widest opacity-50 mb-1">Citations:</p>
                  {msg.grounding.map((g: any, i: number) => g.web && (
                    <a key={i} href={g.web.uri} target="_blank" rel="noopener noreferrer" className="flex items-center text-[10px] hover:underline mb-1">
                      <ExternalLink className="w-3 h-3 mr-1" /> {g.web.title}
                    </a>
                  ))}
                </div>
              )}
              <span className="text-[9px] opacity-30 block mt-2 text-right">
                {msg.timestamp.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
              </span>
            </div>
          </div>
        ))}
        {streamingText && (
          <div className="flex justify-start">
            <div className={`max-w-[85%] p-4 rounded-xl border ${theme.bubbleBot}`}>
              <p className="leading-relaxed whitespace-pre-wrap">{streamingText}</p>
              <span className="inline-block w-1.5 h-4 bg-current animate-pulse ml-1 align-middle"></span>
            </div>
          </div>
        )}
      </div>

      {/* Input */}
      <div className="p-4 border-t border-current/10">
        <div className="flex space-x-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder={isPublic ? "Ask about mission, mandate, or crime trends..." : "EXECUTE SECURE QUERY..."}
            className={`flex-1 px-4 py-3 rounded-lg border focus:outline-none focus:ring-2 transition-all font-sans ${theme.input}`}
          />
          <button 
            onClick={() => handleSend()} 
            disabled={isLoading} 
            className={`p-3 rounded-lg transition-all shadow-md active:scale-95 disabled:opacity-50 ${
              isPublic ? 'bg-veranda-navy text-white' : 'bg-emerald-600 text-zinc-950'
            }`}
          >
            {isLoading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5" />}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ViewState, Member, AppEvent, ForumPost, ForumTopic, LanguageCode, AlumniStory, StoryComment } from '../types';
import { MOCK_MEMBERS, FORUM_TOPICS, MOCK_EVENTS, MOCK_FORUM_POSTS, MEMBERSHIP_TIERS, INTERPOL_LANGUAGES, ALUMNI_STORIES } from '../constants';
import { Archie } from './Archie';
import { analyzeResearchTopic } from '../services/geminiService';
import { 
  Users, Calendar, FileText, Heart, Search, 
  LogOut, ShieldCheck, MessageSquare, Globe,
  Youtube, ExternalLink, PlusCircle, ArrowLeft, BadgeCheck, CreditCard, Award, CheckCircle2, X, Upload, FileCheck, Lock, Paperclip, Sparkles, Loader2,
  Clock, UserCircle, HandHeart, BookOpen, Settings, Check, MessageCircle, Send, Terminal
} from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

interface VaultProps {
  currentView: ViewState;
  onNavigate: (view: ViewState) => void;
  onLogout: () => void;
  isNewUser?: boolean;
}

export const Vault: React.FC<VaultProps> = ({ currentView, onNavigate, onLogout, isNewUser = false }) => {
  const [activeTopic, setActiveTopic] = useState<ForumTopic | null>(null);
  const { t, language, setLanguage } = useLanguage();

  const [selectedLanguage, setSelectedLanguage] = useState<string>('All');
  const [events] = useState<AppEvent[]>(MOCK_EVENTS);
  const [forumTopics] = useState<ForumTopic[]>(FORUM_TOPICS);
  const [rsvpToast, setRsvpToast] = useState<string | null>(null);

  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const [activeStory, setActiveStory] = useState<AlumniStory | null>(null);
  const [donationAmount, setDonationAmount] = useState<string>('50');
  const [isConnected, setIsConnected] = useState<Record<string, boolean>>({});

  const [adviceInput, setAdviceInput] = useState('');
  const [localStories, setLocalStories] = useState<AlumniStory[]>(ALUMNI_STORIES);

  useEffect(() => {
    if (rsvpToast) {
      const timer = setTimeout(() => setRsvpToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [rsvpToast]);

  const handleRunAiAnalysis = async () => {
    if (!activeTopic) return;
    setIsAnalyzing(true);
    const analysis = await analyzeResearchTopic(activeTopic.title, activeTopic.description);
    setAiAnalysis(analysis);
    setIsAnalyzing(false);
  };

  const handleConnect = (id: string) => {
    setIsConnected(prev => ({ ...prev, [id]: true }));
    setRsvpToast("Connection request transmitted.");
  };

  const handleAddAdvice = () => {
    if (!activeStory || !adviceInput.trim()) return;

    const newComment: StoryComment = {
      id: Date.now().toString(),
      author: 'Ross Halliday',
      role: 'Founding Director',
      text: adviceInput,
      timestamp: 'Just now'
    };

    const updatedStories = localStories.map(s => {
      if (s.id === activeStory.id) {
        return {
          ...s,
          comments: [...(s.comments || []), newComment]
        };
      }
      return s;
    });

    setLocalStories(updatedStories);
    setActiveStory(updatedStories.find(s => s.id === activeStory.id) || null);
    setAdviceInput('');
    setRsvpToast("Advice appended to Archive.");
  };

  const SidebarItem = ({ view, icon: Icon, label }: { view: ViewState, icon: any, label: string }) => {
    const disabled = isNewUser && view !== ViewState.VAULT_VERIFICATION && view !== ViewState.VAULT_DASHBOARD;

    return (
      <button 
        disabled={disabled}
        onClick={() => {
          onNavigate(view);
          setActiveTopic(null);
          setAiAnalysis(null);
          setActiveStory(null);
        }}
        className={`w-full flex items-center space-x-3 px-6 py-4 transition-all duration-300 border-l-4 rtl:border-l-0 rtl:border-r-4 ${
          currentView === view 
            ? 'bg-vault-amber/10 border-vault-amber text-vault-amber' 
            : 'border-transparent text-stone-400 hover:text-stone-200 hover:bg-white/5'
        } ${disabled ? 'opacity-30 cursor-not-allowed' : 'cursor-pointer'}`}
      >
        <Icon className="w-5 h-5 rtl:ml-3" />
        <span className="uppercase tracking-widest text-[10px] font-bold">{label}</span>
      </button>
    );
  };

  const renderContent = () => {
    switch (currentView) {
      case ViewState.VAULT_PROFILE:
        return (
          <div className="max-w-4xl mx-auto animate-fade-in-up">
             <div className="bg-white border border-stone-200 shadow-sm rounded-sm overflow-hidden">
                <div className="h-32 bg-vault-charcoal relative">
                   <div className="absolute -bottom-12 left-8 w-24 h-24 rounded-sm border-4 border-white bg-vault-amber flex items-center justify-center text-vault-mahogany font-bold text-3xl">RH</div>
                </div>
                <div className="pt-16 pb-8 px-8 text-stone-900">
                   <div className="flex justify-between items-start mb-6">
                      <div>
                        <h2 className="text-2xl font-serif text-vault-mahogany font-bold">Ross Halliday</h2>
                        <p className="text-stone-500 uppercase tracking-widest text-xs">Founding Director • Board Member</p>
                      </div>
                      <button className="bg-vault-mahogany text-white px-4 py-2 text-[10px] uppercase tracking-widest hover:bg-stone-800 flex items-center space-x-2">
                        <Settings className="w-3 h-3" />
                        <span>Edit Public Identity</span>
                      </button>
                   </div>
                   <div className="grid md:grid-cols-2 gap-8">
                      <div className="space-y-6">
                         <div>
                            <label className="block text-[10px] uppercase tracking-[0.2em] text-stone-400 mb-2 font-bold">Biography</label>
                            <p className="font-serif leading-relaxed text-stone-700">Dedicated to the preservation of institutional memory and the welfare of former Interpol colleagues worldwide.</p>
                         </div>
                      </div>
                   </div>
                </div>
             </div>
          </div>
        );

      case ViewState.VAULT_GIVING:
        return (
          <div className="max-w-4xl mx-auto py-8 text-stone-900">
            <div className="text-center mb-12">
               <HandHeart className="w-16 h-16 text-vault-amber mx-auto mb-4" />
               <h2 className="text-4xl font-serif text-vault-mahogany mb-2">The Legacy Fund</h2>
               <p className="text-stone-500 italic">Supporting retired officials and the Interpol Academy.</p>
            </div>
            <div className="bg-white border border-stone-200 shadow-sm p-10 max-w-2xl mx-auto text-center">
               <h3 className="text-xl font-serif text-vault-mahogany mb-6">Contribute to the Archive</h3>
               <div className="grid grid-cols-4 gap-4 mb-8">
                 {['25', '50', '100', '500'].map(amt => (
                   <button 
                     key={amt} 
                     onClick={() => setDonationAmount(amt)}
                     className={`py-3 border-2 transition-all font-bold ${donationAmount === amt ? 'bg-vault-mahogany text-white border-vault-mahogany' : 'border-stone-200 text-stone-400 hover:border-vault-amber'}`}
                   >
                     ${amt}
                   </button>
                 ))}
               </div>
               <button className="w-full bg-vault-mahogany text-vault-amber py-4 uppercase tracking-[0.2em] text-sm font-bold shadow-lg hover:bg-stone-800 transition-colors">Confirm Contribution</button>
            </div>
          </div>
        );

      case ViewState.VAULT_STORIES:
        if (activeStory) {
          return (
            <div className="max-w-4xl mx-auto animate-fade-in-up">
              <button onClick={() => setActiveStory(null)} className="flex items-center text-stone-400 text-[10px] uppercase font-bold tracking-widest mb-6 hover:text-vault-mahogany transition-colors">
                <ArrowLeft className="w-4 h-4 mr-1" /> Return to Archives
              </button>
              <div className="bg-vault-paper p-12 border-t-8 border-vault-mahogany shadow-2xl mb-12 relative overflow-hidden">
                 <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none"><ShieldCheck className="w-64 h-64 text-vault-mahogany" /></div>
                 <div className="flex justify-between items-center mb-8 border-b border-vault-mahogany/10 pb-4">
                    <span className="text-vault-mahogany/60 font-serif italic text-sm">Case Record File #{activeStory.id}</span>
                    <span className="text-xs uppercase font-bold text-vault-amber bg-vault-mahogany px-3 py-1">{activeStory.year}</span>
                 </div>
                 <h2 className="text-5xl font-serif text-vault-mahogany mb-8 leading-tight">{activeStory.title}</h2>
                 <p className="text-stone-500 text-xs uppercase tracking-[0.3em] mb-10 font-bold">DEPOSITED BY: {activeStory.author.toUpperCase()}</p>
                 <div className="prose prose-stone font-serif text-2xl leading-relaxed text-stone-800 mb-12 pb-12 border-b border-vault-mahogany/10 first-letter:text-7xl first-letter:font-bold first-letter:mr-3 first-letter:float-left first-letter:text-vault-mahogany">
                   {activeStory.fullContent}
                 </div>

                 <div className="bg-white/50 p-8 border-l-4 border-vault-amber shadow-sm">
                    <h3 className="text-sm uppercase tracking-[0.2em] font-bold text-vault-mahogany mb-8 flex items-center">
                       <MessageCircle className="w-5 h-5 mr-3" /> Institutional Advice & Annotations
                    </h3>
                    <div className="space-y-8 mb-10">
                       {activeStory.comments && activeStory.comments.map(comment => (
                         <div key={comment.id} className="border-b border-stone-200 pb-4 last:border-0">
                           <div className="flex justify-between items-start mb-2">
                              <span className="text-xs font-bold text-vault-mahogany">{comment.author} <span className="font-normal text-stone-400 ml-1">({comment.role})</span></span>
                              <span className="text-[10px] text-stone-400 uppercase">{comment.timestamp}</span>
                           </div>
                           <p className="text-base text-stone-700 italic font-serif leading-relaxed">"{comment.text}"</p>
                         </div>
                       ))}
                    </div>

                    <div className="mt-8 bg-white p-4 border border-stone-200 shadow-inner">
                       <label className="block text-[10px] uppercase tracking-widest text-stone-400 mb-3 font-bold">Append your institutional perspective</label>
                       <div className="flex space-x-3">
                          <textarea 
                            value={adviceInput}
                            onChange={(e) => setAdviceInput(e.target.value)}
                            className="flex-1 bg-stone-50 border-none p-4 text-sm font-serif italic text-stone-900 focus:outline-none focus:ring-1 focus:ring-vault-amber"
                            placeholder="Share a perspective on this historical account..."
                            rows={3}
                          />
                          <button 
                            onClick={handleAddAdvice}
                            className="bg-vault-mahogany text-vault-amber px-6 flex flex-col items-center justify-center hover:bg-stone-800 transition-colors shadow-lg"
                          >
                             <Send className="w-5 h-5" />
                             <span className="text-[8px] uppercase mt-2 font-bold tracking-widest">Append</span>
                          </button>
                       </div>
                    </div>
                 </div>
              </div>
            </div>
          );
        }
        return (
          <div className="max-w-6xl mx-auto">
             <div className="flex justify-between items-end mb-12 border-b border-vault-mahogany/20 pb-6">
                <div>
                   <h2 className="text-4xl font-serif text-vault-mahogany">The Oral History Archive</h2>
                   <p className="text-stone-500 font-serif italic mt-2 text-lg">Firsthand accounts from the Saint-Cloud and Lyon eras.</p>
                </div>
                <BookOpen className="w-10 h-10 text-vault-amber opacity-40" />
             </div>
             <div className="grid md:grid-cols-2 gap-10">
               {localStories.map(story => (
                 <div 
                   key={story.id} 
                   onClick={() => setActiveStory(story)} 
                   className="bg-vault-paper p-10 border border-vault-mahogany/10 hover:border-vault-amber shadow-sm hover:shadow-2xl transition-all cursor-pointer group flex flex-col"
                 >
                    <div className="flex justify-between items-start mb-6">
                       <div className="text-[10px] uppercase text-vault-mahogany/50 font-bold tracking-widest">{story.year} • {story.author.toUpperCase()}</div>
                       <div className="flex items-center text-stone-300 group-hover:text-vault-amber transition-colors">
                          <MessageCircle className="w-4 h-4 mr-2" />
                          <span className="text-xs font-bold">{story.comments?.length || 0}</span>
                       </div>
                    </div>
                    <h3 className="text-3xl font-serif text-vault-mahogany group-hover:text-vault-amber transition-colors mb-4 leading-tight">{story.title}</h3>
                    <p className="text-stone-700 line-clamp-4 mb-8 leading-relaxed font-serif text-xl italic flex-grow">"{story.snippet}"</p>
                    <div className="flex flex-wrap gap-2 pt-4 border-t border-vault-mahogany/5">
                      {story.tags.map(tag => (
                        <span key={tag} className="text-[9px] bg-vault-mahogany/5 text-vault-mahogany px-2 py-1 uppercase font-bold tracking-tighter">#{tag}</span>
                      ))}
                    </div>
                 </div>
               ))}
             </div>
          </div>
        );

      case ViewState.VAULT_DIRECTORY:
        const filteredMembers = selectedLanguage === 'All' 
          ? MOCK_MEMBERS 
          : MOCK_MEMBERS.filter(m => m.languages.includes(selectedLanguage));
        return (
          <div className="max-w-6xl mx-auto text-stone-900">
             <div className="flex justify-between items-end mb-8 border-b pb-4">
              <h2 className="text-3xl font-serif text-vault-mahogany">Expertise Directory</h2>
              <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-white border border-stone-300 p-2 text-xs text-stone-900 focus:ring-1 focus:ring-vault-amber outline-none">
                 <option value="All">All Languages</option>
                 {INTERPOL_LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}
              </select>
             </div>
             <div className="grid md:grid-cols-2 gap-8">
               {filteredMembers.map((member: Member) => (
                 <div key={member.id} className="bg-white p-8 border border-stone-200 shadow-sm flex space-x-6 hover:shadow-md transition-shadow group">
                    <img src={member.avatarUrl} alt={member.name} className="w-28 h-28 object-cover grayscale group-hover:grayscale-0 transition-all rounded-sm border border-stone-100" />
                    <div className="flex-1">
                      <div className="flex justify-between items-start mb-2">
                        <h3 className="text-xl font-serif text-vault-mahogany font-bold">{member.name}</h3>
                        {member.isMentor && <span className="text-[8px] bg-vault-amber text-vault-mahogany px-2 py-0.5 font-bold uppercase tracking-widest">Mentor</span>}
                      </div>
                      <p className="text-xs text-stone-500 mb-2 font-bold uppercase tracking-wider">{member.role}</p>
                      <p className="text-xs text-stone-400 mb-4 italic">{member.location} • {member.years}</p>
                      <div className="flex flex-wrap gap-1 mb-6">
                        {member.pillars.map(p => <span key={p} className="text-[8px] border border-stone-200 px-1.5 py-0.5 text-stone-500 uppercase">{p}</span>)}
                      </div>
                      <button 
                        onClick={() => handleConnect(member.id)} 
                        className={`w-full py-2 text-[10px] uppercase tracking-widest font-bold transition-all ${
                          isConnected[member.id] 
                          ? 'bg-stone-100 text-stone-400' 
                          : 'bg-vault-mahogany text-white hover:bg-stone-800'
                        }`}
                      >
                        {isConnected[member.id] ? 'Connected' : 'Transmit Request'}
                      </button>
                    </div>
                 </div>
               ))}
             </div>
          </div>
        );

      case ViewState.VAULT_DASHBOARD:
        return (
          <div className="max-w-5xl mx-auto text-stone-900">
            <h1 className="text-4xl font-serif text-vault-mahogany mb-12 tracking-wide flex items-center">
              {t('vault.welcome')} 
              <span className="ml-4 w-2 h-2 bg-green-500 rounded-full animate-pulse shadow-[0_0_10px_rgba(34,197,94,0.5)]"></span>
            </h1>
            <div className="grid md:grid-cols-4 gap-6">
               <div onClick={() => onNavigate(ViewState.VAULT_ARCHIE)} className="bg-vault-mahogany text-vault-amber p-8 cursor-pointer hover:bg-stone-800 transition-all shadow-xl border-b-4 border-vault-amber group">
                 <Terminal className="w-10 h-10 mb-6 group-hover:scale-110 transition-transform" />
                 <h3 className="text-xl font-serif mb-2">{t('vault.quick.archie')}</h3>
                 <p className="text-[10px] uppercase opacity-50 tracking-widest font-bold">Vault Oracle Interface</p>
               </div>
               <div onClick={() => onNavigate(ViewState.VAULT_STORIES)} className="bg-vault-paper border border-vault-mahogany/10 p-8 cursor-pointer hover:shadow-lg transition-all group">
                 <BookOpen className="w-10 h-10 text-vault-mahogany mb-6 group-hover:scale-110 transition-transform" />
                 <h3 className="text-xl font-serif text-vault-mahogany mb-2">{t('nav.stories')}</h3>
                 <p className="text-[10px] uppercase text-stone-400 tracking-widest font-bold">Oral history archive</p>
               </div>
               <div onClick={() => onNavigate(ViewState.VAULT_FORUM)} className="bg-white border border-stone-200 p-8 cursor-pointer hover:shadow-lg transition-all group">
                 <MessageSquare className="w-10 h-10 text-vault-mahogany mb-6 group-hover:scale-110 transition-transform" />
                 <h3 className="text-xl font-serif text-vault-mahogany mb-2">Briefing Room</h3>
                 <p className="text-[10px] uppercase text-stone-400 tracking-widest font-bold">Peer Discussion</p>
               </div>
               <div className="bg-gradient-to-br from-red-700 to-red-900 text-white p-8 shadow-xl">
                  <Youtube className="w-10 h-10 mb-6" />
                  <h3 className="text-xl font-serif mb-1">Featured</h3>
                  <p className="text-[10px] uppercase opacity-60 tracking-widest font-bold mb-4">Latest Video</p>
                  <a href="https://www.youtube.com/@HallidaysPodcast" target="_blank" rel="noopener noreferrer" className="inline-flex items-center space-x-2 text-[10px] bg-white/10 px-4 py-2 hover:bg-white/20 transition-all font-bold tracking-widest border border-white/20"><ExternalLink className="w-3 h-3" /><span>Watch Briefing</span></a>
               </div>
            </div>

            <div className="mt-16 grid md:grid-cols-2 gap-12">
               <div className="space-y-6">
                 <h2 className="text-xs uppercase tracking-[0.3em] font-bold text-stone-400 border-b pb-2">Upcoming Calendar</h2>
                 <div className="space-y-4">
                    {events.slice(0, 2).map(event => (
                      <div key={event.id} className="flex space-x-4 bg-white p-6 border border-stone-100 shadow-sm">
                        <div className="flex flex-col items-center justify-center bg-vault-mahogany text-vault-amber w-16 h-16 shrink-0">
                           <span className="text-xs font-bold uppercase">{event.date.split('-')[1]}</span>
                           <span className="text-xl font-serif font-bold">{event.date.split('-')[2]}</span>
                        </div>
                        <div className="flex-1">
                          <h4 className="font-serif text-lg text-vault-mahogany">{event.title}</h4>
                          <p className="text-xs text-stone-500 mt-1 uppercase tracking-widest">{event.location}</p>
                        </div>
                      </div>
                    ))}
                    <button onClick={() => onNavigate(ViewState.VAULT_EVENTS)} className="text-[10px] uppercase tracking-widest font-bold text-stone-400 hover:text-vault-mahogany transition-colors">View All Events →</button>
                 </div>
               </div>
               <div className="space-y-6">
                 <h2 className="text-xs uppercase tracking-[0.3em] font-bold text-stone-400 border-b pb-2">Service Status</h2>
                 <div className="bg-vault-charcoal p-8 border-l-8 border-vault-amber text-stone-300">
                    <p className="text-xs uppercase tracking-[0.2em] mb-6 opacity-60">Verified Credentials</p>
                    <div className="flex items-center space-x-4 mb-8">
                       <div className="w-14 h-14 bg-vault-amber rounded-full flex items-center justify-center text-vault-mahogany font-serif text-2xl font-bold">RH</div>
                       <div>
                          <h3 className="text-xl text-white font-serif">Ross Halliday</h3>
                          <p className="text-[10px] uppercase tracking-[0.2em] text-vault-amber font-bold">Legacy Fellow • Founding Director</p>
                       </div>
                    </div>
                    <div className="space-y-3">
                       <div className="flex items-center text-[10px] uppercase tracking-widest text-green-500"><CheckCircle2 className="w-4 h-4 mr-2" /> Identity Confirmed</div>
                       <div className="flex items-center text-[10px] uppercase tracking-widest text-green-500"><CheckCircle2 className="w-4 h-4 mr-2" /> Article 3 Compliant</div>
                    </div>
